// Script: generar_126_colores_categorias_tarjetas.js
// Agrega color de fondo por categoria en las tarjetas de Chiqui te cuenta:
//   🍎 Alimentacion → naranja suave  (#FEF3E7)
//   🩺 Salud        → verde suave    (#EAF6EF)
//   🧠 Comportamiento → morado suave (#F3EEFF)
//   🏃 Bienestar    → azul suave     (#EBF6FC)
//   🌿 Seguridad    → rojo suave     (#FDEAEA)
// Cada tarjeta muestra el fondo, el borde y el titulo en el color
// de su categoria. Incluye un badge pequeno con el nombre de la categoria.

const fs = require('fs'); const path = require('path');
function escribir(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64,'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir,{recursive:true});
  fs.writeFileSync(filePath, content, 'utf8');
  console.log('OK: ' + filePath);
}
escribir('components/ChiquiTeCuenta.tsx', "");
escribir('app/analisis/page.tsx', "");
